//-- Led on
//-- - - - - - - - - - - - - - - - - - - - - - - - --
//-- 
//---------------------------------------------------

module v023069_vde0592 (
 input Clk_i,
 input [3:0] InRow,
 output [3:0] OScan,
 output [4:0] Data
);
 
 reg [2:0] Clk_Count;
 reg [3:0] rO_Scan;
 reg [4:0] r1Dat,r2Dat,r3Dat,r4Dat,rData;
 
 always @(posedge Clk_i) begin
     Clk_Count = Clk_Count+1;
     case(Clk_Count)
         0:  OScan = 4'b0111;
         1:  r1Dat = (InRow[3]==0) ? 5'h01 : 
                     (InRow[2]==0) ? 5'h02 : 
                     (InRow[1]==0) ? 5'h03 : 
                     (InRow[0]==0) ? 5'h0a : 5'h1f ;
         2:  OScan = 4'b1011;
         3:  r2Dat = (InRow[3]==0) ? 5'h04 : 
                     (InRow[2]==0) ? 5'h05 : 
                     (InRow[1]==0) ? 5'h06 : 
                     (InRow[0]==0) ? 5'h0b : 5'h1f ;
         4:  OScan = 4'b1101;
         5:  r3Dat = (InRow[3]==0) ? 5'h07 : 
                     (InRow[2]==0) ? 5'h08 : 
                     (InRow[1]==0) ? 5'h09 : 
                     (InRow[0]==0) ? 5'h0c : 5'h1f ;
         6:  OScan = 4'b1110;
         7:  r4Dat = (InRow[3]==0) ? 5'h0e : 
                     (InRow[2]==0) ? 5'h00 : 
                     (InRow[1]==0) ? 5'h0f : 
                     (InRow[0]==0) ? 5'h0d : 5'h1f ;
         endcase
     rData = (r1Dat != 5'h1f) ? r1Dat :
             (r2Dat != 5'h1f) ? r2Dat :
             (r3Dat != 5'h1f) ? r3Dat :
             (r4Dat != 5'h1f) ? r4Dat : rData;
     end
     
 assign  OScan = rO_Scan;
 assign  Data  = rData;
endmodule
